#include "ASTBuilder.h"
#include "asg/Asg.h"
#include <nlohmann/json.hpp>
#include "antlr4-runtime.h"

using namespace asg;
using json = nlohmann::json;

json ASTBuilder::buildJSON(const Node* node) const {
    if (!node) return json{};

    switch (node->kind) {
        case Node::kFunctionDecl:
            return buildFunctionDecl(static_cast<const FunctionDecl*>(node));
        case Node::kVarDecl:
            return buildVarDecl(static_cast<const VarDecl*>(node));
        case Node::kCompoundStmt:
            return buildCompoundStmt(static_cast<const CompoundStmt*>(node));
        default:
            return buildExpr(static_cast<const Expr*>(node));
    }
}

json ASTBuilder::buildFunctionDecl(const FunctionDecl* node) const {
    json j;
    j["kind"] = "FunctionDecl";
    j["name"] = node->name;

    if (node->type) {
        j["returnType"] = node->type->spec == asg::Type::Spec::kInt ? "int" : "void";
    }

    if (node->body) {
        j["body"] = buildJSON(node->body);
    }

    return j;
}

json ASTBuilder::buildVarDecl(const VarDecl* node) const {
    json j;
    j["kind"] = "VarDecl";
    j["name"] = node->name;

    if (node->type) {
        j["type"] = node->type->spec == asg::Type::Spec::kInt ? "int" : "void";
    }

    if (node->init) {
        j["init"] = buildJSON(node->init);
    }

    return j;
}

json ASTBuilder::buildCompoundStmt(const CompoundStmt* node) const {
    json j;
    j["kind"] = "CompoundStmt";

    json items = json::array();
    for (auto stmt : node->subs) {
        items.push_back(buildJSON(stmt));
    }
    j["items"] = items;

    return j;
}

json ASTBuilder::buildExpr(const Expr* expr) const {
    if (!expr) return json{};

    switch (expr->kind) {
        case Node::kIntegerLiteral: {
            auto lit = static_cast<const IntegerLiteral*>(expr);
            return {
                {"kind", "IntegerLiteral"},
                {"value", lit->val}
            };
        }
        case Node::kDeclRefExpr: {
            auto ref = static_cast<const DeclRefExpr*>(expr);
            return {
                {"kind", "DeclRefExpr"},
                {"name", ref->decl->name}
            };
        }
        case Node::kBinaryExpr: {
            auto bin = static_cast<const BinaryExpr*>(expr);
            return {
                {"kind", "BinaryExpr"},
                {"op", bin->op == asg::BinaryExpr::Op::kAdd ? "+" : "="},
                {"lft", buildJSON(bin->lft)},
                {"rht", buildJSON(bin->rht)}
            };
        }
        default:
            return {
                {"kind", "UnknownExpr"}
            };
    }
}

FunctionDecl* ASTBuilder::makeFunction(antlr4::ParserRuleContext* declCtx, antlr4::ParserRuleContext* bodyCtx) const {
    // Implementation to create FunctionDecl from context
    return new FunctionDecl();
}

std::vector<Decl*> ASTBuilder::makeDeclaration(antlr4::ParserRuleContext* specCtx, antlr4::ParserRuleContext* initCtx) const {
    // Implementation to create declarations from context
    return {};
}

