json toJson(asg::Node* node) {
    if (node == nullptr) return json{};

    json j;
    switch (node->kind) {
        case asg::Node::kTranslationUnit: {
            auto tu = static_cast<asg::TranslationUnit*>(node);
            j["kind"] = "TranslationUnit";
            j["decls"] = json::array();
            for (auto decl : tu->decls) {
                j["decls"].push_back(toJson(decl));
            }
