    std::vector<llvm::Type*> pty;
    for (auto param : p->params) {
      pty.push_back(self(param));
  }
    return llvm::FunctionType::get(self(&subt), std::move(pty), false);
  }

  ABORT();
}

//==============================================================================
// 表达式
//==============================================================================

llvm::Value*
EmitIR::operator()(Expr* obj)
{
  if (auto p = obj->dcst<DeclRefExpr>())
    return self(p);
  if (auto p = obj->dcst<BinaryExpr>())
    return self(p);
  if (auto p = obj->dcst<UnaryExpr>())
    return self(p);
  if (auto p = obj->dcst<CallExpr>())
    return self(p);
  if (auto p = obj->dcst<IntegerLiteral>())
    return self(p);
  ABORT();
}

llvm::Constant*
EmitIR::operator()(IntegerLiteral* obj)
{
  return llvm::ConstantInt::get(self(obj->type), obj->val);
}

llvm::Value*
EmitIR::operator()(DeclRefExpr* obj)
{
    auto& irb = *mCurIrb;
    auto decl = obj->decl->dcst<VarDecl>();
    if (!decl) ABORT();

    if (auto alloca = llvm::dyn_cast<llvm::AllocaInst>(decl->any)) {
        return irb.CreateLoad(self(decl->type), alloca, decl->name);
    }
    else if (auto gvar = llvm::dyn_cast<llvm::GlobalVariable>(decl->any)) {
        return irb.CreateLoad(self(decl->type), gvar, decl->name);
    }
    ABORT();
}

llvm::Value*
EmitIR::operator()(BinaryExpr* obj)
{
    auto& irb = *mCurIrb;
    auto lft = self(obj->lft);
    auto rht = self(obj->rht);

    switch (obj->op) {
        case BinaryExpr::Op::kAdd:
            return irb.CreateAdd(lft, rht, "addtmp");
        case BinaryExpr::Op::kSub:
            return irb.CreateSub(lft, rht, "subtmp");
        case BinaryExpr::Op::kMul:
            return irb.CreateMul(lft, rht, "multmp");
        case BinaryExpr::Op::kDiv:
            return irb.CreateSDiv(lft, rht, "divtmp");
        case BinaryExpr::Op::kAssign:
            if (auto declRef = obj->lft->dcst<DeclRefExpr>()) {
                auto decl = declRef->decl->dcst<VarDecl>();
                if (!decl) ABORT();

                if (auto alloca = llvm::dyn_cast<llvm::AllocaInst>(decl->any)) {
                    return irb.CreateStore(rht, alloca);
                }
                else if (auto gvar = llvm::dyn_cast<llvm::GlobalVariable>(decl->any)) {
                    return irb.CreateStore(rht, gvar);
                }
            }
            ABORT();
        default:
            ABORT();
    }
}

llvm::Value*
EmitIR::operator()(UnaryExpr* obj)
{
    auto& irb = *mCurIrb;
    auto sub = self(obj->sub);

    switch (obj->op) {
        case UnaryExpr::Op::kNeg:
            return irb.CreateNeg(sub, "negtmp");
        default:
            ABORT();
    }
}

llvm::Value*
EmitIR::operator()(CallExpr* obj)
{
    auto& irb = *mCurIrb;

    // Look up function
    auto func = llvm::dyn_cast<llvm::Function>(mMod.getFunction(obj->head->dcst<DeclRefExpr>()->decl->name));
    if (!func) ABORT();

    // Prepare arguments
    std::vector<llvm::Value*> args;
    for (auto arg : obj->args) {
        args.push_back(self(arg));
    }

    return irb.CreateCall(func, args, "calltmp");
}

//==============================================================================
// 语句
//==============================================================================

void
EmitIR::operator()(Stmt* obj)
{
  // TODO: 在此添加对更多Stmt类型的处理的跳转

  if (auto p = obj->dcst<CompoundStmt>())
    return self(p);

  if (auto p = obj->dcst<ReturnStmt>())
    return self(p);

  ABORT();
}

// TODO: 在此添加对更多Stmt类型的处理

void
EmitIR::operator()(CompoundStmt* obj)
{
  // TODO: 可以在此添加对符号重名的处理
  for (auto&& stmt : obj->subs)
    self(stmt);
}

void
EmitIR::operator()(ReturnStmt* obj)
{
  auto& irb = *mCurIrb;

  llvm::Value* retVal;
  if (!obj->expr)
    retVal = nullptr;
  else
    retVal = self(obj->expr);

  mCurIrb->CreateRet(retVal);

  auto exitBb = llvm::BasicBlock::Create(mCtx, "return_exit", mCurFunc);
  mCurIrb->SetInsertPoint(exitBb);
}

//==============================================================================
// 声明
//==============================================================================

void
EmitIR::operator()(Decl* obj)
{
  // TODO: 添加变量声明处理的跳转

  if (auto p = obj->dcst<FunctionDecl>())
    return self(p);

  ABORT();
}

void
EmitIR::operator()(VarDecl* obj)
{
    // Create global variable
    if (mCurFunc == nullptr) {
        auto gvar = new llvm::GlobalVariable(
            mMod,
            self(obj->type),
            false,
            llvm::GlobalValue::ExternalLinkage,
            nullptr,
            obj->name);
        obj->any = gvar;

        // Handle initialization
        if (obj->init) {
            auto init = self(obj->init);
            gvar->setInitializer(llvm::dyn_cast<llvm::Constant>(init));
        }
    }
    // Create local variable
    else {
        auto& irb = *mCurIrb;
        auto alloca = irb.CreateAlloca(self(obj->type), nullptr, obj->name);
        obj->any = alloca;

        // Handle initialization
        if (obj->init) {
            auto init = self(obj->init);
            irb.CreateStore(init, alloca);
        }
    }
}

void
EmitIR::operator()(FunctionDecl* obj)
{
  // 创建函数
  auto fty = llvm::dyn_cast<llvm::FunctionType>(self(obj->type));
  auto func = llvm::Function::Create(
    fty, llvm::GlobalVariable::ExternalLinkage, obj->name, mMod);

  obj->any = func;

  if (obj->body == nullptr)
    return;
  auto entryBb = llvm::BasicBlock::Create(mCtx, "entry", func);
  mCurIrb->SetInsertPoint(entryBb);
  auto& entryIrb = *mCurIrb;

  auto argIt = func->arg_begin();
  for (auto param : obj->params) {
      auto arg = &*argIt++;
      arg->setName(param->name);
      param->any = arg;
  }

  // 翻译函数体
  mCurFunc = func;
  self(obj->body);
  auto& exitIrb = *mCurIrb;

  if (fty->getReturnType()->isVoidTy())
    exitIrb.CreateRetVoid();
  else
    exitIrb.CreateUnreachable();
}

