        auto func = astBuilder.makeFunction($declarator.ctx, $compoundStatement.ctx);
        printAST(func);
    }
    ;

declaration
    :   declarationSpecifiers initDeclaratorList? Semi
    {
        auto decls = astBuilder.makeDeclaration($declarationSpecifiers.ctx, $initDeclaratorList.ctx);
        for (auto decl : decls) {
            printAST(decl);
        }
    }
    ;

declarationSpecifiers
    :   typeSpecifier+
    ;

typeSpecifier
    :   Int
    |   Void
    ;

declarator
    :   Identifier
    |   declarator LeftBracket RightBracket
    |   declarator LeftBracket assignmentExpression RightBracket
    |   declarator LeftParen RightParen
    |   declarator LeftParen parameterList RightParen
    ;

initDeclaratorList
    :   initDeclarator (Comma initDeclarator)*
    ;

initDeclarator
    :   declarator
    |   declarator Equal initializer
    ;

initializer
    :   assignmentExpression
    |   LeftBrace initializerList RightBrace
    |   LeftBrace RightBrace
    ;

initializerList
    :   initializer (Comma initializer)*
    ;

compoundStatement
    :   LeftBrace blockItemList? RightBrace
    ;

blockItemList
    :   blockItem+
    ;

blockItem
    :   statement
    |   declaration
    ;

statement
    :   compoundStatement
    |   expressionStatement
    |   jumpStatement
    ;

expressionStatement
    :   expression? Semi
    ;

jumpStatement
    :   Return expression? Semi
    ;

expression
    :   assignmentExpression (Comma assignmentExpression)*
    ;

assignmentExpression
    :   logicalOrExpression
    |   unaryExpression Equal assignmentExpression
    ;

logicalOrExpression
    :   logicalAndExpression
    ;

logicalAndExpression
    :   equalityExpression
    ;

equalityExpression
    :   relationalExpression
    ;

relationalExpression
    :   additiveExpression
    ;

additiveExpression
    :   multiplicativeExpression
    |   additiveExpression Plus multiplicativeExpression
    |   additiveExpression Minus multiplicativeExpression
    ;

multiplicativeExpression
    :   unaryExpression
    ;

unaryExpression
    :   postfixExpression
    |   Minus unaryExpression
    ;

postfixExpression
    :   primaryExpression
    |   postfixExpression LeftParen RightParen
    |   postfixExpression LeftParen argumentExpressionList RightParen
    ;

primaryExpression
    :   Identifier
    |   Constant
    |   LeftParen expression RightParen
    ;

parameterList
    :   parameterDeclaration (Comma parameterDeclaration)*
    ;

parameterDeclaration
    :   declarationSpecifiers declarator
    ;

argumentExpressionList
    :   assignmentExpression (Comma assignmentExpression)*
    ;

